shapes.frame_eqs_str:
tm=q1;

xp=0;
yp=0.1;
zp=0;

//wrist movement;
ang=sin(tm*2 )*0.5 +0.5;

xq=xp;
sinang=sin(ang);cosang=cos(ang);
yq=yp*sinang + zp*cosang;
zq=yp*cosang - zp*sinang;
yq=yp;
zq=zp;

ang=tm*8;
sinang=sin(ang);cosang=cos(ang);
xp=xq*sinang + yq*cosang;
yp=xq*cosang - yq*sinang;
zp=zq;

//forearm movement;
zp=zp-0.3;
ang=3.14 + sin(tm*2 - 0.5)*1.5;
sinang=sin(ang);cosang=cos(ang);
xq=xp;
yq=yp*sinang + zp*cosang;
zq=yp*cosang - zp*sinang;

//upper arm twist
ang=-1.0 + cos(tm*3.1 + 0.5);
sinang=sin(ang);cosang=cos(ang);
xp=xq*sinang + yq*cosang;
yp=xq*cosang - yq*sinang;
zp=zq;

//upper arm outward;
zp=zp-0.35;
ang=cos(tm*2.3)*1.75 - 1.05;
sinang=sin(ang);cosang=cos(ang);
xq=xp*sinang + zp*cosang;
yq=yp;
zq=xp*cosang - zp*sinang;

//upper arm up down;
ang=cos(tm)*0.5 - 0.5;
sinang=sin(ang);cosang=cos(ang);
xp=xq;
yp=yq*cosang - zq*sinang;
zp=yq*sinang + zq*cosang;

//xp=xq;yp=yq;zp=zq;


//project into screenspace and draw on screen
zp=zp+2;
xs=xp/zp;
ys=yp/zp;

x=xs+0.5;
y=ys*1.3+0.5;

warp:
shader_body { 
 vec4 tmpvar_1;
 tmpvar_1.w = 1.0;
 float tmpvar_2;
 tmpvar_2 = dot (texsize.zw, texsize.zw);
 vec2 tmpvar_3;
 tmpvar_3 = (uv - 0.5);
 tmpvar_1.xyz = (max (max (texture (sampler_main, uv).xyz, texture (sampler_main, 
   ((tmpvar_3 * (1.0 - (8.0 * 
     sqrt(tmpvar_2)
   ))) + 0.5)
 ).xyz), texture (sampler_main, (
   (tmpvar_3 * (1.0 + (8.0 * sqrt(tmpvar_2))))
  + 0.5)).xyz) - 0.03);
 ret = tmpvar_1.xyz;
}

comp:
shader_body { 
 vec3 ret_1;
 ret_1 = (mix (texture (sampler_main, uv).xyz, texture (sampler_main, (
   (0.5 - uv)
  + 0.5)).xyz, vec3(0.5, 0.5, 0.5)) * 2.0);
 vec3 tmpvar_2;
 tmpvar_2 = (1.0 - ((ret_1 * 
   (1.0 - ret_1)
 ) * 4.0));
 vec3 tmpvar_3;
 tmpvar_3.xy = (tmpvar_2.xy * vec2(0.5, 0.5));
 tmpvar_3.z = tmpvar_2.z;
 vec3 tmpvar_4;
 tmpvar_4 = pow (tmpvar_3, (1.2 - tmpvar_3));
 ret_1 = tmpvar_4;
 vec4 tmpvar_5;
 tmpvar_5.w = 1.0;
 tmpvar_5.xyz = tmpvar_4;
 ret = tmpvar_5.xyz;
}
